def gen(rng, size):
    n = max(1, min(size, 400))
    # build node list with random structure honoring 'single child must be left'
    val_pool = list(range(1, 10**9))
    rng.shuffle(val_pool)
    nodes = []  # each: [val, left_idx, right_idx]
    nodes.append([val_pool[0], None, None])
    for k in range(1, n):
        # attach as child of a random existing node with a free slot
        candidates = []
        for idx, nd in enumerate(nodes):
            if nd[1] is None or nd[2] is None:
                candidates.append(idx)
        p = rng.choice(candidates)
        new_idx = len(nodes)
        nodes.append([val_pool[k], None, None])
        if nodes[p][1] is None:
            nodes[p][1] = new_idx
        else:
            nodes[p][2] = new_idx
    parts = []
    def serialize(idx, depth):
        parts.append('-' * depth + str(nodes[idx][0]))
        if nodes[idx][1] is not None:
            serialize(nodes[idx][1], depth + 1)
        if nodes[idx][2] is not None:
            serialize(nodes[idx][2], depth + 1)
    serialize(0, 0)
    return [''.join(parts)]

