class Solution:
    def recoverFromPreorder(self, traversal):
        # Brute force recursive parse: split into (depth, val) tokens, then
        # recursively carve out the left and right subtree spans.
        tokens = []
        i = 0
        s = traversal
        while i < len(s):
            d = 0
            while i < len(s) and s[i] == '-':
                d += 1
                i += 1
            j = i
            while j < len(s) and s[j] != '-':
                j += 1
            tokens.append((d, int(s[i:j])))
            i = j
        def build(items, depth):
            if not items:
                return None
            node = TreeNode(items[0][1])
            # find boundaries of children at depth+1
            rest = items[1:]
            # split rest into segments each starting at depth+1
            children = []
            cur = []
            for tok in rest:
                if tok[0] == depth + 1:
                    if cur:
                        children.append(cur)
                    cur = [tok]
                else:
                    cur.append(tok)
            if cur:
                children.append(cur)
            if len(children) >= 1:
                node.left = build(children[0], depth + 1)
            if len(children) >= 2:
                node.right = build(children[1], depth + 1)
            return node
        return build(tokens, 0)

