class Solution:
    def recoverFromPreorder(self, traversal):
        stack = []
        i = 0
        s = traversal
        while i < len(s):
            depth = 0
            while i < len(s) and s[i] == '-':
                depth += 1
                i += 1
            j = i
            while j < len(s) and s[j] != '-':
                j += 1
            val = int(s[i:j])
            i = j
            node = TreeNode(val)
            while len(stack) > depth:
                stack.pop()
            if stack:
                parent = stack[-1]
                if parent.left is None:
                    parent.left = node
                else:
                    parent.right = node
            stack.append(node)
        return stack[0] if stack else None

